        //-----------------------------------------------------------------------------------
        //ищем локомотив в процессе zlauncher.exe
        //-----------------------------------------------------------------------------------
        public static int find_loco()
        {
            //Получаем minimum и maximum адресс
            SYSTEM_INFO sys_info = new SYSTEM_INFO();
            GetSystemInfo(out sys_info);

            /******* Список модулей процесса *******/
            List<ProcessModule> m_module = new List<ProcessModule>();

            int i_name = 0;
            for (int i = 0; i < current_process.Modules.Count; i++)
            {
                m_module.Add(current_process.Modules[i]);

                if (Convert.ToString(m_module[i].ModuleName) == "Launcher.exe")
                {
                    BA = m_module[i].BaseAddress;
                    i_name = 2;
                }
              
                if (Convert.ToString(m_module[i].ModuleName) == "OpenAL32.dll")
                {
                    BA_openal32 = m_module[i].BaseAddress;
                    i_openal32_select = 1;
                }
                else i_openal32_select = 0;
            }

            /******* Получаем базовый адрес модуля *******/
            IntPtr proc_min_address = sys_info.minimumApplicationAddress;
            IntPtr proc_max_address = sys_info.maximumApplicationAddress;

            //сохранение значений в виде длинных целых чисел, так что мне не придется делать много приведений позже
            long proc_min_address_l = (long)proc_min_address;
            long proc_max_address_l = (long)proc_max_address;

            if (i_name == 2)
            {
                Process process = Process.GetProcessesByName("launcher")[0];
                //открытие процесса с желаемым уровнем доступа
                IntPtr processHandle = OpenProcess(PROCESS_QUERY_INFORMATION | PROCESS_VM_READ | PROCESS_VM_WRITE | PROCESS_VM_OPERATION, false, process.Id);

            }

            //здесь будет храниться любая информация, которую мы получаем от VirtualQueryEx()
            //MEMORY_BASIC_INFORMATION mem_basic_info = new MEMORY_BASIC_INFORMATION();
            sig_loco = 0;

            //Читаем из памяти процеса игры версию ZD simulator
            temp_buffer = read_bytes((int)BA + 0x0000011d, 1);

            //статические ZD simulator v54.006
            if (temp_buffer[0] == 0x9c)
            {
                i_process_name = 6;//версия 54.006

                //читаем путь zdsim
                int i_flag_string = 0;

                for (int i = 0; i_flag_string < 2; i++)
                {
                    temp_buffer = read_bytes((Int32)BA_openal32 + 0x00dacfc + i, 1);
                    if (temp_buffer[0] != 0)
                    {
                        i_flag_string = 0;
                        temp_buffer2[i] = temp_buffer[0];
                    }
                    else i_flag_string++;

                    temp_buffer3 = new byte[i];
                    Array.Copy(temp_buffer2, 0, temp_buffer3, 0, i);
                }

                s_path_zdsim_sound = Encoding.ASCII.GetString(temp_buffer3);
                s_path_zdsim_sound = s_path_zdsim_sound.Remove(s_path_zdsim_sound.LastIndexOf(@"\Lau") + 1);
                s_path_zdsim_sound = s_path_zdsim_sound + "sound";

                int i_temp1 = 0;
                temp_buffer = read_bytes((int)BA + 0x003E79A0, 4);
                i_temp1 = BitConverter.ToInt32(temp_buffer, 0) + 0x633;
                temp_buffer = read_bytes(i_temp1, 8);
                string s_temp = BitConverter.ToString(temp_buffer);
                s_temp = s_temp.Replace("-", "");


                if (s_temp.Equals(sig_2es5k) == true) sig_loco = 1;
                if (s_temp.Equals(sig_ep1m) == true) sig_loco = 2;
                if (s_temp.Equals(sig_chs2k) == true) sig_loco = 3;
                if (s_temp.Equals(sig_chs4) == true) sig_loco = 4;
                if (s_temp.Equals(sig_chs4kvr) == true) sig_loco = 5;
                if (s_temp.Equals(sig_chs4t) == true) sig_loco = 6;
                if (s_temp.Equals(sig_chs7) == true) sig_loco = 7;
                if (s_temp.Equals(sig_chs8) == true) sig_loco = 8;
                if (s_temp.Equals(sig_vl11m) == true) sig_loco = 9;
                if (s_temp.Equals(sig_vl82m) == true) sig_loco = 10;
                if (s_temp.Equals(sig_vl80t) == true) sig_loco = 11;
                if (s_temp.Equals(sig_vl85) == true) sig_loco = 12;
                if (s_temp.Equals(sig_tep70) == true) sig_loco = 13;
                if (s_temp.Equals(sig_2te10u) == true) sig_loco = 14;
                if (s_temp.Equals(sig_m62) == true) sig_loco = 15;
                if (s_temp.Equals(sig_ed4m) == true) sig_loco = 16;
                if (s_temp.Equals(sig_ed9m) == true) sig_loco = 17;
                if (s_temp.Equals(sig_tem18) == true) sig_loco = 18;
            }

            InitBuffers();
            return sig_loco;
        }

        //-----------------------------------------------------------------------------------
