                //-------------------------------------------------------------------------
                //Лампа 3 круг Утечка ТМ 0x39c4
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x39c4, 1);

                //(3круг Утечка ТМ 0x39c4 == 1) или (1круг Утечка ТМ 0x39c4 == 1) или (2круг Утечка ТМ 0x39c4 == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[1] == 1 || temp_buffer3[1] == 1)
                {
                    temp_buffer[0] = 1;
                }
                else
                {
                    temp_buffer[0] = 0;
