                //(3круг С2 0x6229 == 1) или (1круг С2 0x6229 == 1) или (2круг С2 0x6229 == 1) или ((3круг С1 == 1) или (3круг С2 == 1))
                if (temp_buffer[0] == 1 || temp_buffer2[3] == 1 || temp_buffer3[3] == 1 || out_buffer[45] == 1)
                {
                    temp_buffer[0] = 1;
                }
                else
                {
                    temp_buffer[0] = 0;
                }

                Array.Copy(temp_buffer, 0, out_buffer, 45, 1);

                //-------------------------------------------------------------------------
                //Лампа ВВ откр1 отсуствует
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 46, 1);

                //-------------------------------------------------------------------------
                //Лампа Вспом. комп. отсуствует
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 47, 1);

                //-------------------------------------------------------------------------
                //Лампа Комп1 отсуствует
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
