                //(Вент1. 0x6229 == 1) или (1круг Вент1 0x6bc8 == 1) или (2круг Вент1 0x6bc8 == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[4] == 1 || temp_buffer3[4] == 1)
