                temp_buffer = read_bytes(sig_pos_elektro + 0x64e8, 1);

                //(rp_850_gv 0x64e8 == 1) или (
                if (temp_buffer[0] == 1 || temp_buffer2[25] == 1)
                {
                    temp_buffer[0] = 1;
                }
                else
                {
                    temp_buffer[0] = 0;
                }
                Array.Copy(temp_buffer, 0, out_buffer, 50, 1);

                //-------------------------------------------------------------------------
                //Лампа zemla_bv отсуствует
