                //-------------------------------------------------------------------------
                //Лампа Ход прав отсуствует
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 56, 1);
            }
            return out_buffer;
        }

