                temp_buffer = read_bytes(sig_pos_elektro + 0x3BA9, 1);
                if (temp_buffer[0] == 1 || temp_buffer2[3] == 1 || temp_buffer3[3] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, temp_buffer2, 100, 1);
                //вент3
                temp_buffer = read_bytes(sig_pos_elektro + 0x3C85, 1);
                if (temp_buffer[0] == 1 || temp_buffer2[4] == 1 || temp_buffer3[4] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, temp_buffer2, 101, 1);
                //вент5
                temp_buffer = read_bytes(sig_pos_elektro + 0x3D61, 1);
                if (temp_buffer[0] == 1 || temp_buffer2[5] == 1 || temp_buffer3[5] == 1 || temp_buffer2[100] == 1 || temp_buffer2[101] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 49, 1);
                //гв
                temp_buffer = read_bytes(sig_pos_elektro + 0x4181, 1);
                if (temp_buffer[0] == 1 || temp_buffer2[6] == 1 || temp_buffer3[6] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 50, 1);
                //земля1
                temp_buffer = read_bytes(sig_pos_elektro + 0x4FC5, 1);
                if (temp_buffer[0] == 1 || temp_buffer2[7] == 1 || temp_buffer3[7] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 51, 1);
                //РК 0_1
                temp_buffer = read_bytes(sig_pos_elektro + 0x59E9, 1);
                if (temp_buffer[0] == 1 || temp_buffer2[8] == 1 || temp_buffer3[8] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 52, 1);
                //РК пром. 1
                temp_buffer = read_bytes(sig_pos_elektro + 0x57D9, 1);
                if (temp_buffer[0] == 1 || temp_buffer2[9] == 1 || temp_buffer3[9] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 53, 1);
                //песок
                temp_buffer = read_bytes(sig_pos_elektro + 0x6C79, 1);
                if (temp_buffer[0] == 1 || temp_buffer2[10] == 1 || temp_buffer3[10] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 54, 1);
                //насос
                temp_buffer = read_bytes(sig_pos_elektro + 0x73DD, 1);
                if (temp_buffer[0] == 1 || temp_buffer2[11] == 1 || temp_buffer3[11] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 55, 1);

                //ход прав
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 56, 1);
            }
            return out_buffer;
        }

        //-----------------------------------------------------------------------------------
        // Функция читает из памяти игры параметры локомотива "Электровоз ЧС4Т"
        //-----------------------------------------------------------------------------------
        public static byte[] read_chs4t(int sig_pos_pnevm = 0, int sig_pos_elektro = 0)
        {
            if (i_process_name == 6)
            {
                //-------------------------------------------------------------------------
                //                               статические
                //-------------------------------------------------------------------------
                //-------------------------------------------------------------------------
                //скорость доп.
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x0032CA78, 2);
                Form1.i_skor_dop = BitConverter.ToInt16(temp_buffer, 0);

                //-------------------------------------------------------------------------
                //скорость тек.
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x04F6FCE0, 4);
                float f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                UInt16 i_temp = Convert.ToUInt16(f_temp * i_skor_tek_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 2, 2);

                //-------------------------------------------------------------------------
                //Светофор АЛС
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08BEB744, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 4, 1);

                //-------------------------------------------------------------------------
                //Лампа бдительность
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x0032CBC0, 1);
                i_bdit_current = temp_buffer[0];

                //-------------------------------------------------------------------------
                //скор тек 2
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x04F6FCE0, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp);
                Form1.i_skor_tek = i_temp;
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 6, 2);

                //-------------------------------------------------------------------------
                //Ток эпт
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4E4, 8);
                double d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_tok_ept_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 8, 2);

                //-------------------------------------------------------------------------
                //Время часы
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8AC, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 10, 1);

                //-------------------------------------------------------------------------
                //Время минуты
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8B0, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 11, 1);

                //-------------------------------------------------------------------------
