                Thread.Sleep(10);

                //-------------------------------------------------------------------------
                //                           лампы 3 круг
                //-------------------------------------------------------------------------
                //Лампа 3 круг утечка ТМ отсуствует
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 44, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг ТД отсуствует
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 45, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг ВВ_откр1 0x4C29
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x4C29, 1);

                //(3круг ВВ_откр1 0x4C29 == 1) или (1круг ВВ_откр1 0x4C29 == 1) или (2круг ВВ_откр1 0x4C29 == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[1] == 1 || temp_buffer3[1] == 1)
                {
                    temp_buffer[0] = 1;
                }
                else
                {
                    temp_buffer[0] = 0;
                }

                Array.Copy(temp_buffer, 0, out_buffer, 46, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг вспом.комп. 0x2F49
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x2F49, 1);

                //(3круг вспом.комп. 0x2F49 == 1) или (1круг вспом.комп. 0x2F49 == 1) или (2круг вспом.комп. 0x2F49 == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[2] == 1 || temp_buffer3[2] == 1)
                {
                    temp_buffer[0] = 1;
                }
                else
                {
                    temp_buffer[0] = 0;
                }
                Array.Copy(temp_buffer, 0, out_buffer, 47, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг комп1 0x66F9
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x66F9, 1);

                //(3круг комп1 0x66F9 == 1) или (1круг комп1 0x66F9 == 1) или (1круг комп2 0x6961 == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[3] == 1 || temp_buffer2[4] == 1)
