                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, temp_buffer2, 100, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг комп2 0x6961
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x6961, 1);

                //(3круг комп2 0x6961 == 1) или (2круг комп1 0x66F9 == 1) или (2круг комп2 0x6961 == 1) или ((3круг комп1 0x66F9 == 1) или (1круг комп1 0x66F9 == 1) или (1круг комп2 0x6961 == 1))
                if (temp_buffer[0] == 1 || temp_buffer3[3] == 1 || temp_buffer3[4] == 1 || temp_buffer2[100] == 1)
                {
                    temp_buffer[0] = 1;
                }
                else
                {
                    temp_buffer[0] = 0;
                }
                Array.Copy(temp_buffer, 0, out_buffer, 48, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг Вент1 0x5DB1
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x5DB1, 1);

                //(3круг Вент1 0x5DB1 == 1) или (1круг Вент1 0x5DB1 == 1) или (1круг Вент3 0x5E61 == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[5] == 1 || temp_buffer2[6] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, temp_buffer2, 100, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг Вент3 0x5E61
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x5E61, 1);

                //(3круг Вент3 0x5E61 == 1) или (2круг Вент1 0x5DB1 == 1) или (2круг Вент3 0x5E61 == 1) или ((3круг Вент1 0x5DB1 == 1) или (1круг Вент1 0x5DB1 == 1) или (1круг Вент3 0x5E61 == 1))
                if (temp_buffer[0] == 1 || temp_buffer3[5] == 1 || temp_buffer3[6] == 1 || temp_buffer2[100] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 49, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг рп850_1 0x6AC1
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x6AC1, 1);

                //(3круг рп850_1 0x6AC1 == 1) или (1круг рп850_1 0x6AC1 == 1) или (2круг рп850_1 0x6AC1 == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[7] == 1 || temp_buffer3[7] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 50, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг земля1 0x77FD
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x77FD, 1);

                //(3круг земля1 0x77FD == 1) или (1круг земля1 0x77FD == 1) или (2круг земля1 0x77FD == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[8] == 1 || temp_buffer3[8] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 51, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг РК0_1 0x8699
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x8699, 1);

                //(3круг РК0_1 0x8699 == 1) или (1круг РК0_1 0x8699 == 1) или (2круг РК0_1 0x8699 == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[9] == 1 || temp_buffer3[9] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                { 
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 52, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг РК пром.1 0x7B6D
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x7B6D, 1);

                //(3круг РКпром.1 0x7B6D == 1) или (1круг РКпром.1 0x7B6D == 1) или (2круг РКпром.1 0x7B6D == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[10] == 1 || temp_buffer3[10] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 53, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг Песок 0xAD9D
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0xAD9D, 1);

                //(3круг Песок 0xAD9D == 1) или (1круг Песок 0xAD9D == 1) или (2круг Песок 0xAD9D == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[11] == 1 || temp_buffer3[11] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 54, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг утечка насос 0x12ED
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x12ED, 1);

                //(3круг утечка насос 0x12ED == 1) или (1круг Насос 0x12ED == 1) или (2круг Насос 0x12ED == 1)
                if (temp_buffer[0] == 1 || temp_buffer2[12] == 1 || temp_buffer3[12] == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 55, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг ход прав отсуствует
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 56, 1);
            }
            return out_buffer;
        }

        //-----------------------------------------------------------------------------------
        // Функция читает из памяти игры параметры локомотива "Электровоз ЧС7"
        //-----------------------------------------------------------------------------------
        public static byte[] read_chs7(int sig_pos_pnevm = 0, int sig_pos_elektro = 0)
        {
            if (i_process_name == 6)
            {
                //статические
                //скорость доп.
                temp_buffer = read_bytes((Int32)BA + 0x0032CA78, 2);
                Form1.i_skor_dop = BitConverter.ToInt16(temp_buffer, 0);

                //скорость тек.
                temp_buffer = read_bytes((Int32)BA + 0x04F6FCE0, 4);
                float f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                UInt16 i_temp = Convert.ToUInt16(f_temp * i_skor_tek_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 2, 2);

                //АЛС
                temp_buffer = read_bytes((Int32)BA + 0x08BEB744, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 4, 1);

                //бдительность
                temp_buffer = read_bytes((Int32)BA + 0x0032CBC0, 1);
                i_bdit_current = temp_buffer[0];

                //скор тек 2
                temp_buffer = read_bytes((Int32)BA + 0x04F6FCE0, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp);
                Form1.i_skor_tek = i_temp;
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 6, 2);

                //ток эпт
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4E4, 8);
                double d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_tok_ept_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 8, 2);

                //час
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8AC, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 10, 1);

                //минута
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8B0, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 11, 1);

                //секунда
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8B4, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 12, 1);

                //напруга float
                temp_buffer = read_bytes((Int32)BA + 0x08CF3F30, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp * i_napruga_ks_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 13, 2);

                //контроллер поз.
                temp_buffer = new byte[] { 0, 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 15, 2);

                //напруга тд
                temp_buffer = new byte[] { 0, 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 17, 2);

                //ток1
                temp_buffer = read_bytes((Int32)BA + 0x08DB9360, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp / i_tok_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 19, 2);

                //ток2
                temp_buffer = read_bytes((Int32)BA + 0x08DB9364, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp / i_tok_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 21, 2);

                //ток3
                temp_buffer = read_bytes((Int32)BA + 0x08DB9368, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp / i_tok_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 23, 2);

                //ток4
                temp_buffer = read_bytes((Int32)BA + 0x08DB936C, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp / i_tok_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 25, 2);

                //РК поз1
                temp_buffer = new byte[] { 255, 255 };
                Array.Copy(temp_buffer, 0, out_buffer, 27, 2);

                //динамические
                //НМ float
                temp_buffer = read_bytes(sig_pos_pnevm + 0x58, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 29, 2);

                //ТМ float
                temp_buffer = read_bytes(sig_pos_pnevm + 0x30, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 31, 2);

                //УР float
                temp_buffer = read_bytes(sig_pos_pnevm + 0xa8, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 33, 2);

                //ТЦ float
                temp_buffer = read_bytes(sig_pos_pnevm + 0x80, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 35, 2);

                //-------------------------------------------------------------------------
                //                               Лампы
                //-------------------------------------------------------------------------
                //Лампа ТЦ
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_pnevm + 0x80, 8); //читаем давление тц
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                if (d_temp <= 0.3)
                {
                    temp_buffer = new byte[] { 0 };
                }
                else
                {
                    temp_buffer = new byte[] { 1 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 37, 1);

                //-------------------------------------------------------------------------
                //Лампа ЭПТ О
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4D1, 1); //читаем эпт контроль
                byte b_temp1 = temp_buffer[0];
                if (b_temp1 == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                { 
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 38, 1);

                //-------------------------------------------------------------------------
                //Лампа ЭПТ П
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4D1, 1); //читаем эпт контроль
                b_temp1 = temp_buffer[0];
                temp_buffer = read_bytes((Int32)BA + 0x0032CBD0, 1); //читаем кран 395
                byte b_temp2 = temp_buffer[0];
                if (b_temp1 == 1 && (b_temp2 == 2 || b_temp2 == 3))
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 39, 1);

                //-------------------------------------------------------------------------
                //Лампа эпт Т
                //------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4D1, 1); //читаем эпт контроль
                b_temp1 = temp_buffer[0];
                temp_buffer = read_bytes((Int32)BA + 0x0032CBD0, 1); //читаем кран 395
                b_temp2 = temp_buffer[0];

                if (b_temp1 == 1 && (b_temp2 == 4 || b_temp2 == 5 || b_temp2 == 6))
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 40, 1);

                //-------------------------------------------------------------------------
                //Лампа РК С
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08CF3F9C, 4); //читаем РК поз.
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                if (f_temp >= 1 && f_temp <= 20)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                {
                    temp_buffer = new byte[] { 0 };
                }
                Array.Copy(temp_buffer, 0, out_buffer, 41, 1);

                //-------------------------------------------------------------------------
                //Лампа РК СП
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08CF3F9C, 4); //читаем РК поз.
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                if (f_temp >= 21 && f_temp <= 38)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 42, 1);

                //-------------------------------------------------------------------------
                //Лампа РК П
                //-------------------------------------------------------------------------
                temp_buffer = read_bytes((Int32)BA + 0x08CF3F9C, 4); //читаем РК поз.
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                if (f_temp >= 39 && f_temp <= 56)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 43, 1);

                //-------------------------------------------------------------------------
                //                          лампы 3 круг
                //-------------------------------------------------------------------------
                //Лампа 3 круг утечка ТМ
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 44, 1);

                //тд
                temp_buffer = read_bytes((Int32)BA + 0x08CF3F9C, 4); //читаем РК поз.
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                if (f_temp == 0)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 45, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг ВВ откр1 
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 46, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг вспом. комп.
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 47, 1);

                //комп2
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 48, 1);

                //-------------------------------------------------------------------------
                //Лампа 3 круг Вент3 
                //-------------------------------------------------------------------------
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 49, 1);

                //850
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 50, 1);

                //земля1
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 51, 1);

                //РК 0_1
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 52, 1);

                //РК пром. 1
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 53, 1);

                //песок
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 54, 1);

                //насос
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 55, 1);

                //ход прав
                temp_buffer = read_bytes((Int32)BA + 0x08CF3F9C, 4); //читаем РК поз.
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                if (f_temp == 20 || f_temp == 38 || f_temp == 56)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 56, 1);
            }
            return out_buffer;
        }

