                //--------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x564D, 1);
                Array.Copy(temp_buffer, 0, temp_buffer3, 8, 1);

                if (temp_buffer[0] == 1 || temp_buffer2[8] == 1 || temp_buffer3[8] == 1 || temp_buffer2[100] == 1)
                    temp_buffer[0] = 1;
                else
                    temp_buffer[0] = 0;

                Array.Copy(temp_buffer, 0, out_buffer, 49, 1);

                //--------------------------------------------------------------------------
                //Лампа ГВ лев
                //--------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x5049, 1);

                if (temp_buffer[0] == 1 || temp_buffer2[9] == 1 || temp_buffer3[9] == 1)
                    temp_buffer[0] = 1;
                else
                    temp_buffer[0] = 0;

                Array.Copy(temp_buffer, 0, out_buffer, 50, 1);

                //--------------------------------------------------------------------------
                //Лампа РЗ
                //--------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x83AD, 1);

                if (temp_buffer[0] == 1 || temp_buffer2[10] == 1 || temp_buffer3[10] == 1)
                    temp_buffer[0] = 1;
                else
                    temp_buffer[0] = 0;

                Array.Copy(temp_buffer, 0, out_buffer, 51, 1);

                //--------------------------------------------------------------------------
                //Лампа ГВ прав
                //--------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x4FC5, 1);

                if (temp_buffer[0] == 1 || temp_buffer2[11] == 1 || temp_buffer3[11] == 1)
