                else
                    temp_buffer[0] = 0;

                Array.Copy(temp_buffer, 0, out_buffer, 53, 1);

                //--------------------------------------------------------------------------
                //Лампа РБ Боксование 
                //--------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x5CA8, 1);

                if (temp_buffer[0] == 1 || temp_buffer2[13] == 1 || temp_buffer3[13] == 1)
                    temp_buffer[0] = 1;
                else
                    temp_buffer[0] = 0;

                Array.Copy(temp_buffer, 0, out_buffer, 54, 1);

                //--------------------------------------------------------------------------
                //Лампа ФР
                //--------------------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_elektro + 0x57AD, 1);

                if (temp_buffer[0] == 1 || temp_buffer2[14] == 1 || temp_buffer3[14] == 1)
