                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 33, 2);

                //ТЦ float
                temp_buffer = read_bytes(sig_pos_pnevm + 0xa8, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 35, 2);

                //Лампы
                //тц
                temp_buffer = read_bytes(sig_pos_pnevm + 0xa8, 8); //читаем давление тц
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                if (d_temp <= 0.3)
                {
                    temp_buffer = new byte[] { 0 };
                }
                else
                    temp_buffer = new byte[] { 1 };
                Array.Copy(temp_buffer, 0, out_buffer, 37, 1);

                //эпт О
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4D1, 1); //читаем эпт контроль
                byte b_temp1 = temp_buffer[0];
                if (b_temp1 == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 38, 1);

                //эпт П
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4D1, 1); //читаем эпт контроль
                b_temp1 = temp_buffer[0];
                temp_buffer = read_bytes((Int32)BA + 0x0032CBD0, 1); //читаем кран 395
                byte b_temp2 = temp_buffer[0];
                if (b_temp1 == 1 && (b_temp2 == 2 || b_temp2 == 3))
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 39, 1);

                //эпт Т
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4D1, 1); //читаем эпт контроль
                b_temp1 = temp_buffer[0];
                temp_buffer = read_bytes((Int32)BA + 0x0032CBD0, 1); //читаем кран 395
                b_temp2 = temp_buffer[0];
                if (b_temp1 == 1 && (b_temp2 == 4 || b_temp2 == 5 || b_temp2 == 6))
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 40, 1);

            }
            return out_buffer;
        }

        //-----------------------------------------------------------------------------------
        // Функция читает из памяти игры параметры локомотива "Тепловоз М62"
        //-----------------------------------------------------------------------------------
        public static byte[] read_m62(int sig_pos_pnevm = 0, int sig_pos_elektro = 0)
        {
            if (i_process_name == 6)
            {
                //статические

                //скорость доп.
                temp_buffer = new byte[] { 255, 255 };
                Array.Copy(temp_buffer, 0, out_buffer, 0, 2);
                //скорость тек.
                temp_buffer = read_bytes((Int32)BA + 0x04F6FCE0, 4);
                float f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                UInt16 i_temp = Convert.ToUInt16(f_temp * i_skor_tek_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 2, 2);
                //АЛС
                temp_buffer = read_bytes((Int32)BA + 0x08BEB744, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 4, 1);
                //бдительность
                temp_buffer = read_bytes((Int32)BA + 0x0032CBC0, 1);
                i_bdit_current = temp_buffer[0];
                //скор тек 2
                temp_buffer = read_bytes((Int32)BA + 0x04F6FCE0, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp);
                Form1.i_skor_tek = i_temp;
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 6, 2);
                //ток эпт
                temp_buffer = new byte[] { 0, 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 8, 2);
                //час
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8AC, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 10, 1);
                //минута
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8B0, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 11, 1);
                //секунда
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8B4, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 12, 1);
                //напруга float
                temp_buffer = new byte[] { 0, 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 13, 2);
                //контроллер поз.
                temp_buffer = new byte[] { 0, 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 15, 2);

                //напруга тд
                temp_buffer = read_bytes((Int32)BA + 0x04F6FA38, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp / i_napruga_td_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 17, 2);

                //ток1
                temp_buffer = read_bytes((Int32)BA + 0x04F6FCC8, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp / i_tok_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 19, 2);

                //ток2
                temp_buffer = new byte[] { 0, 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 21, 2);
                //ток3
                temp_buffer = new byte[] { 0, 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 23, 2);
                //ток4
                temp_buffer = new byte[] { 0, 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 25, 2);
                //РК поз1
                temp_buffer = new byte[] { 255, 255 };
                Array.Copy(temp_buffer, 0, out_buffer, 27, 2);

                //динамические

                //НМ float
                temp_buffer = read_bytes(sig_pos_pnevm + 0x80, 8);
                double d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 29, 2);
                //ТМ float
                temp_buffer = read_bytes(sig_pos_pnevm + 0x58, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 31, 2);
                //УР float
                temp_buffer = read_bytes(sig_pos_pnevm + 0x30, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 33, 2);
                //ТЦ float
                temp_buffer = read_bytes(sig_pos_pnevm + 0xa8, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 35, 2);

                //Лампы

                //тц
                temp_buffer = read_bytes(sig_pos_pnevm + 0xa8, 8); //читаем давление тц
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                if (d_temp <= 0.3)
                {
                    temp_buffer = new byte[] { 0 };
                }
                else
                    temp_buffer = new byte[] { 1 };
                Array.Copy(temp_buffer, 0, out_buffer, 37, 1);
                //эпт О
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 38, 1);
                //эпт П
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 39, 1);
                //эпт Т
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 40, 1);

                //РК С
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 41, 1);
                //РК СП
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 42, 1);
                //РК П
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 43, 1);


                //лампы 3 круг

                //утечка ТМ
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 44, 1);

                //тд
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 45, 1);

                //вв откр1
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 46, 1);
                //вспом. комп.
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 47, 1);
                //комп2
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 48, 1);
                //вент3
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 49, 1);
                //850
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 50, 1);
                //земля1
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 51, 1);
                //РК 0_1
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 52, 1);
                //РК пром. 1
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 53, 1);
                //песок
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 54, 1);
                //насос
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 55, 1);

                //ход прав
                temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 56, 1);
            }
            return out_buffer;
        }

        //-----------------------------------------------------------------------------------
        // Функция читает из памяти игры параметры локомотива "Электропоезд ЭД4М"
        //-----------------------------------------------------------------------------------
        public static byte[] read_ed4m(int sig_pos_pnevm = 0, int sig_pos_elektro = 0)
        {
            if (i_process_name == 6)
            {
                //скорость доп         2-байта    out_buffer - 0
                //скорость тек         2-байта    out_buffer - 2
                //АЛС                  1-байт     out_buffer - 4
                //бдительность         1-байт     out_buffer - 5
                //скор тек2            2-байта    out_buffer - 6
                //резерв               2-байт     out_buffer - 8
                //час                  1-байт     out_buffer - 10
                //минута               1-байт     out_buffer - 11
                //секунда              1-байт     out_buffer - 12
                //Напряжение кс        2-байта    out_buffer - 13
                //контроллер           1-байт     out_buffer - 15
                //резерв               1-байт     out_buffer - 16
                //резерв               2-байт     out_buffer - 17
                //резерв               2-байт     out_buffer - 19
                //резерв               2-байт     out_buffer - 21
                //резерв               2-байт     out_buffer - 23
                //резерв               1-байт     out_buffer - 25
                //резерв               1-байт     out_buffer - 26
                //резерв               1-байт     out_buffer - 27
                //резерв               1-байт     out_buffer - 28
                //Манометр НМ          2-байта    out_buffer - 29 
                //Манометр ТМ          2-байта    out_buffer - 31
                //Манометр УР          2-байта    out_buffer - 33
                //Манометр ТЦ          2-байта    out_buffer - 35
                //Лампа ТЦ             1-байт     out_buffer - 37
                //Лампа эпт-О          1-байт     out_buffer - 38
                //Лампа эпт-П          1-байт     out_buffer - 39
                //Лампа эпт-Т          1-байт     out_buffer - 40
                //Лампа ПР ZTE         1-байт     out_buffer - 41 Ok
                //Лампа ВЦ ZTE         1-байт     out_buffer - 42 OK
                //EPK_State SIM        1-байт     out_buffer - 43 OK
                //Лампа ЛК ZTE         1-байт     out_buffer - 44 OK
                //Лампа ЛК SIM         1-байт     out_buffer - 45 OK
                //Лампа двери SIM      1-байт     out_buffer - 46 OK
                //Лампа двери ZTE      1-байт     out_buffer - 47 OK
                //Лампа О и Т ZTE      1-байт     out_buffer - 48 OK
                //Лампа РН ZTE         1-байт     out_buffer - 49 OK
                //Лампа РН SIM         1-байт     out_buffer - 50 OK
                //Лампа БВ SIM         1-байт     out_buffer - 51 OK
                //Лампа БВ ZTE         1-байт     out_buffer - 52 OK
                //Лампа К ZTE          1-байт     out_buffer - 53 OK
                //Лампа РБ Бокс. SIM   1-байт     out_buffer - 54 OK
                //Лампа СОТ   ZTE      1-байт     out_buffer - 55 OK
                //Лампа СОТx  ZTE      1-байт     out_buffer - 56 OK

                byte[] b;
                Int32 i32;

                //статические
                //скорость доп.
                temp_buffer = read_bytes((Int32)BA + 0x0032CA78, 2);
                Form1.i_skor_dop = BitConverter.ToInt16(temp_buffer, 0);

                //скорость тек.
                temp_buffer = read_bytes((Int32)BA + 0x04F6FCE0, 4);
                float f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                UInt16 i_temp = Convert.ToUInt16(f_temp * i_skor_tek_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 2, 2);

                //АЛС
                temp_buffer = read_bytes((Int32)BA + 0x08BEB744, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 4, 1);

                //бдительность
                temp_buffer = read_bytes((Int32)BA + 0x0032CBC0, 1);
                i_bdit_current = temp_buffer[0];

                //скор тек 2
                temp_buffer = read_bytes((Int32)BA + 0x04F6FCE0, 4);
                f_temp = BitConverter.ToSingle(temp_buffer, 0);
                f_temp = Math.Abs(f_temp);
                i_temp = Convert.ToUInt16(f_temp);
                Form1.i_skor_tek = i_temp;
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 6, 2);

                //час
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8AC, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 10, 1);

                //минута
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8B0, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 11, 1);

                //секунда
                temp_buffer = read_bytes((Int32)BA + 0x08BEB8B4, 1);
                Array.Copy(temp_buffer, 0, out_buffer, 12, 1);

                //Напряжение контактной сети. float
                temp_buffer = read_bytes((Int32)BA + 0x08DB92B4, 8);
                double d_temp = BitConverter.ToDouble(temp_buffer, 0);
                d_temp = Math.Abs(d_temp);
                i_temp = Convert.ToUInt16(d_temp * i_napruga_ks_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 13, 2);

                //читаем контроллер
                byte[] b_temp_byte1 = new byte[1] { 0 };             //обнуляем массив
                b_temp_byte1 = read_bytes((Int32)BA + 0x08DB92AD, 1);//читаем контроллер
                temp_buffer = read_bytes((Int32)BA + 0x08DB92AD, 1); //читаем контроллер
                Array.Copy(temp_buffer, 0, out_buffer, 15, 1);


                //динамические
                //Манометр НМ. float
                temp_buffer = read_bytes(sig_pos_pnevm + 0x58, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 29, 2);

                //ТМ float
                temp_buffer = read_bytes(sig_pos_pnevm + 0x30, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 31, 2);

                //УР float
                temp_buffer = read_bytes(sig_pos_pnevm + 0xa8, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 33, 2);

                //ТЦ float
                temp_buffer = read_bytes(sig_pos_pnevm + 0x80, 8);
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                i_temp = Convert.ToUInt16(d_temp * i_pnevmo_convert);
                temp_buffer = BitConverter.GetBytes(i_temp);
                Array.Copy(temp_buffer, 0, out_buffer, 35, 2);
                //---------------------------------------------------------------
                //Лампы
                //---------------------------------------------------------------
                //тц SIM
                //---------------------------------------------------------------
                temp_buffer = read_bytes(sig_pos_pnevm + 0x80, 8); //читаем давление тц
                d_temp = BitConverter.ToDouble(temp_buffer, 0);
                if (d_temp <= 0.3)
                {
                    temp_buffer = new byte[] { 0 };
                }
                else
                    temp_buffer = new byte[] { 1 };
                Array.Copy(temp_buffer, 0, out_buffer, 37, 1);
                //---------------------------------------------------------------
                //эпт О SIM
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4D1, 1); //читаем эпт контроль
                byte b_temp1 = temp_buffer[0];
                if (b_temp1 == 1)
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 38, 1);
                //---------------------------------------------------------------
                //эпт П SIM
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4D1, 1); //читаем эпт контроль
                b_temp1 = temp_buffer[0];
                temp_buffer = read_bytes((Int32)BA + 0x0032CBD0, 1); //читаем кран 395
                byte b_temp2 = temp_buffer[0];

                if (b_temp1 == 1 && (b_temp2 == 2 || b_temp2 == 3 || b_temp_byte1[0] == 255 || b_temp_byte1[0] == 254 || b_temp_byte1[0] == 253))
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };

                Array.Copy(temp_buffer, 0, out_buffer, 39, 1);
                //---------------------------------------------------------------
                //эпт Т SIM
                temp_buffer = read_bytes((Int32)BA + 0x08BEB4D1, 1); //читаем эпт контроль
                b_temp1 = temp_buffer[0];
                temp_buffer = read_bytes((Int32)BA + 0x0032CBD0, 1); //читаем кран 395
                b_temp2 = temp_buffer[0];
                if (b_temp1 == 1 && (b_temp2 == 4 || b_temp2 == 5 || b_temp2 == 6 || b_temp_byte1[0] == 252 || b_temp_byte1[0] == 251))
                {
                    temp_buffer = new byte[] { 1 };
                }
                else
                    temp_buffer = new byte[] { 0 };
                Array.Copy(temp_buffer, 0, out_buffer, 40, 1);
                //---------------------------------------------------------------
                //Лампа ПР ZTE
                temp_buffer = read_bytes((Int32)BA + 0x0145FFFB, 1);//читаем ПР ZTE
                b_temp1 = temp_buffer[0];
                if (b_temp1 != 0)
                    temp_buffer = new byte[] { 0 };
                else
                    temp_buffer = new byte[] { 1 };
                Array.Copy(temp_buffer, 0, out_buffer, 41, 1);
                //---------------------------------------------------------------
                //Лампа ВЦ ZTE
                temp_buffer = read_bytes((Int32)BA + 0x0145FFFC, 1);//читаем ВЦ ZTE
                b_temp1 = temp_buffer[0];
                if (b_temp1 != 0)
                    temp_buffer = new byte[] { 0 };
                else
                    temp_buffer = new byte[] { 1 };
                Array.Copy(temp_buffer, 0, out_buffer, 42, 1);
                //---------------------------------------------------------------
                //EPK_State SIM
                b = read_bytes((Int32)BA + 0x07905ACC, 4); //читаем состояние ключа EPK
                i32 = BitConverter.ToInt32(b, 0) + 0x38;
                if (i32 != 0)
                    temp_buffer = new byte[] { 0 };
                else
                    temp_buffer = new byte[] { 1 };
                Array.Copy(temp_buffer, 0, out_buffer, 43, 1);
                //---------------------------------------------------------------
                //Лампа ЛК ZTE
                temp_buffer = read_bytes((Int32)BA + 0x0145FFF8, 1); //двери ZTE
                b_temp1 = temp_buffer[0];
                if (b_temp1 != 0)
                    temp_buffer = new byte[] { 0 };
                else
                    temp_buffer = new byte[] { 1 };
                Array.Copy(temp_buffer, 0, out_buffer, 44, 1);

                //Лампа ЛК SIM
                temp_buffer = read_bytes((Int32)BA + 0x08DB92AD, 1); //читаем контроллер
                b_temp1 = temp_buffer[0];
                if (b_temp1 == 0)//если 0, сбрасываем флаги
                {
                    i_lampa_LK = 0;
                    i_lampa_LK_flag = 0;
                    Form1.i_lampa_LK_sec_flag = 0;
                }

                //если х1 или т1 после 0 и не вышел таймер 500ms, зажигаем ЛК
                if ((b_temp1 == 1 || b_temp1 == 255) && i_lampa_LK_flag == 0
                     && out_buffer[50] == 0 && out_buffer[51] == 0)
                {
                    i_lampa_LK = 1;
                    i_lampa_LK_flag = 1;
                }
                temp_buffer = BitConverter.GetBytes(i_lampa_LK);
                Array.Copy(temp_buffer, 0, out_buffer, 45, 1);
                //---------------------------------------------------------------
                //двери SIM
                temp_buffer = read_bytes((Int32)BA + 0x08BE7C28, 1);
                b_temp1 = temp_buffer[0];
                temp_buffer = read_bytes((Int32)BA + 0x08BE7C29, 1);
                b_temp2 = temp_buffer[0];
                if (b_temp1 == 1 && b_temp2 == 1)
                {
                    i_dvery_current = 1;
                }

                if (b_temp1 == 0 || b_temp2 == 0)
                {
                    i_dvery_current = 0;
                }

                //двери ZTE
                temp_buffer = read_bytes((Int32)BA + 0x0145FFFA, 1); //двери ZTE
                b_temp1 = temp_buffer[0];
                if (b_temp1 != 0)
                    temp_buffer = new byte[] { 0 };
                else
                    temp_buffer = new byte[] { 1 };
                Array.Copy(temp_buffer, 0, out_buffer, 47, 1);
                //---------------------------------------------------------------
                //Лампа О и Т ZTE
                temp_buffer = read_bytes((Int32)BA + 0x0145FFFF, 1);//читаем О и Т ZTE
                b_temp1 = temp_buffer[0];
                if (b_temp1 != 0)
                    temp_buffer = new byte[] { 0 };
                else
                    temp_buffer = new byte[] { 1 };
